CREATE TABLE IF NOT EXISTS pmo_raid_items (raid_id UUID PRIMARY KEY DEFAULT gen_random_uuid(), correlation_id TEXT, item_type TEXT NOT NULL, title TEXT NOT NULL, description TEXT, severity TEXT NOT NULL DEFAULT 'medium', probability NUMERIC(4,3), impact TEXT, owner TEXT, status TEXT NOT NULL DEFAULT 'open', mitigation TEXT, due_date TIMESTAMPTZ, source TEXT, evidence JSONB NOT NULL DEFAULT '{}'::jsonb, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW());
CREATE TABLE IF NOT EXISTS pmo_action_items (action_id UUID PRIMARY KEY DEFAULT gen_random_uuid(), correlation_id TEXT, source TEXT, title TEXT NOT NULL, description TEXT, owner TEXT, priority TEXT NOT NULL DEFAULT 'medium', status TEXT NOT NULL DEFAULT 'open', due_date TIMESTAMPTZ, evidence JSONB NOT NULL DEFAULT '{}'::jsonb, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), closed_at TIMESTAMPTZ);
CREATE TABLE IF NOT EXISTS pmo_health_snapshots (snapshot_id BIGSERIAL PRIMARY KEY, correlation_id TEXT, health_score INTEGER NOT NULL, health_status TEXT NOT NULL, summary TEXT, metrics JSONB NOT NULL DEFAULT '{}'::jsonb, recommendations JSONB NOT NULL DEFAULT '[]'::jsonb, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW());
CREATE TABLE IF NOT EXISTS ai_decisions (decision_id UUID PRIMARY KEY DEFAULT gen_random_uuid(), correlation_id TEXT, agent_role TEXT, decision_type TEXT, input_summary TEXT, recommendation TEXT, confidence DOUBLE PRECISION, risk_level TEXT, requires_human_approval BOOLEAN, status TEXT, created_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE IF NOT EXISTS estado_tareas (id BIGSERIAL PRIMARY KEY, card_id TEXT NOT NULL DEFAULT 'unknown', card_nombre TEXT, lista_nombre TEXT, miembro_nombre TEXT, fecha_vencimiento TIMESTAMPTZ, completada BOOLEAN NOT NULL DEFAULT FALSE, adjuntos_count INTEGER NOT NULL DEFAULT 0, fecha TIMESTAMPTZ NOT NULL DEFAULT NOW());
CREATE TABLE IF NOT EXISTS events_outbox (outbox_id BIGSERIAL PRIMARY KEY, event_id TEXT, target TEXT NOT NULL DEFAULT 'discord', action TEXT NOT NULL DEFAULT 'notify', idempotency_key TEXT, payload JSONB NOT NULL DEFAULT '{}'::jsonb, status TEXT NOT NULL DEFAULT 'pending', retry_count INTEGER NOT NULL DEFAULT 0, scheduled_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), sent_at TIMESTAMPTZ, last_error TEXT, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW());
CREATE TABLE IF NOT EXISTS events_inbox (event_id TEXT PRIMARY KEY, source TEXT, event_type TEXT, received_at TIMESTAMPTZ DEFAULT NOW(), correlation_id TEXT, actor TEXT, processing_status TEXT DEFAULT 'pending', retry_count INTEGER DEFAULT 0, last_error TEXT, payload JSONB DEFAULT '{}'::jsonb, normalized JSONB DEFAULT '{}'::jsonb);
CREATE TABLE IF NOT EXISTS card_attachments (attachment_id TEXT PRIMARY KEY, card_id TEXT, card_name TEXT, filename TEXT, url TEXT, summary_extracted TEXT, added_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE IF NOT EXISTS pmo_meetings (meeting_id UUID PRIMARY KEY DEFAULT gen_random_uuid(), title TEXT NOT NULL, status TEXT NOT NULL DEFAULT 'proposed', priority TEXT, scheduled_for TIMESTAMPTZ, requested_by TEXT, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW());

ALTER TABLE pmo_meetings ADD COLUMN IF NOT EXISTS idempotency_key TEXT;
ALTER TABLE pmo_meetings ADD COLUMN IF NOT EXISTS correlation_id TEXT;
ALTER TABLE pmo_meetings ADD COLUMN IF NOT EXISTS source TEXT;
ALTER TABLE pmo_meetings ADD COLUMN IF NOT EXISTS objective TEXT;
ALTER TABLE pmo_meetings ADD COLUMN IF NOT EXISTS context_summary TEXT;
ALTER TABLE pmo_meetings ADD COLUMN IF NOT EXISTS requested_for TIMESTAMPTZ;
ALTER TABLE pmo_meetings ADD COLUMN IF NOT EXISTS duration_minutes INTEGER NOT NULL DEFAULT 30;
ALTER TABLE pmo_meetings ADD COLUMN IF NOT EXISTS timezone TEXT NOT NULL DEFAULT 'America/Guayaquil';
ALTER TABLE pmo_meetings ADD COLUMN IF NOT EXISTS scheduling_status TEXT;
ALTER TABLE pmo_meetings ADD COLUMN IF NOT EXISTS scheduling_notes TEXT;
ALTER TABLE pmo_meetings ADD COLUMN IF NOT EXISTS calendar_provider TEXT;
ALTER TABLE pmo_meetings ADD COLUMN IF NOT EXISTS calendar_event_id TEXT;
ALTER TABLE pmo_meetings ADD COLUMN IF NOT EXISTS calendar_url TEXT;
ALTER TABLE pmo_meetings ADD COLUMN IF NOT EXISTS updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW();
SELECT
  json_build_object(
    'approvals_pending', (SELECT COUNT(*) FROM ai_decisions WHERE status = 'pending_approval'),
    'approvals_high', (SELECT COUNT(*) FROM ai_decisions WHERE status = 'pending_approval' AND risk_level IN ('high','critical')),
    'tasks_open', (SELECT COUNT(*) FROM estado_tareas WHERE completada = false),
    'tasks_overdue', (SELECT COUNT(*) FROM estado_tareas WHERE completada = false AND fecha_vencimiento < NOW()),
    'tasks_due_48h', (SELECT COUNT(*) FROM estado_tareas WHERE completada = false AND fecha_vencimiento BETWEEN NOW() AND NOW() + INTERVAL '48 hours'),
    'outbox_dead', (SELECT COUNT(*) FROM events_outbox WHERE status = 'dead'),
    'outbox_pending', (SELECT COUNT(*) FROM events_outbox WHERE status IN ('pending','sending')),
    'inbox_failed', (SELECT COUNT(*) FROM events_inbox WHERE processing_status IN ('error','failed')),
    'inbox_backlog', (SELECT COUNT(*) FROM events_inbox WHERE processing_status IN ('pending','processing','ingested')),
    'docs_pending', (SELECT COUNT(*) FROM card_attachments WHERE summary_extracted IS NULL),
    'meetings_open', (SELECT COUNT(*) FROM pmo_meetings WHERE status IN ('proposed','scheduled')),
    'raid_open_high', (SELECT COUNT(*) FROM pmo_raid_items WHERE status = 'open' AND severity IN ('high','critical')),
    'actions_overdue', (SELECT COUNT(*) FROM pmo_action_items WHERE status = 'open' AND due_date < NOW()),
    'actions_open', (SELECT COUNT(*) FROM pmo_action_items WHERE status = 'open')
  ) AS stats,
  COALESCE((SELECT json_agg(t) FROM (SELECT card_id, card_nombre, lista_nombre, miembro_nombre, fecha_vencimiento FROM estado_tareas WHERE completada = false AND fecha_vencimiento < NOW() ORDER BY fecha_vencimiento ASC LIMIT 10) t), '[]'::json) AS overdue_tasks,
  COALESCE((SELECT json_agg(t) FROM (SELECT decision_id, agent_role, input_summary, recommendation, risk_level, created_at FROM ai_decisions WHERE status = 'pending_approval' ORDER BY created_at ASC LIMIT 10) t), '[]'::json) AS pending_approvals,
  COALESCE((SELECT json_agg(t) FROM (SELECT outbox_id, action, retry_count, last_error, scheduled_at FROM events_outbox WHERE status = 'dead' ORDER BY scheduled_at DESC LIMIT 10) t), '[]'::json) AS dead_outbox,
  COALESCE((SELECT json_agg(t) FROM (SELECT event_id, source, event_type, retry_count, last_error, received_at FROM events_inbox WHERE processing_status IN ('error','failed') ORDER BY received_at DESC LIMIT 10) t), '[]'::json) AS failed_events,
  COALESCE((SELECT json_agg(t) FROM (SELECT attachment_id, card_name, filename, added_at FROM card_attachments WHERE summary_extracted IS NULL ORDER BY added_at DESC LIMIT 10) t), '[]'::json) AS docs_pending,
  COALESCE((SELECT json_agg(t) FROM (SELECT title, status, priority, scheduled_for, requested_by FROM pmo_meetings WHERE status IN ('proposed','scheduled') ORDER BY scheduled_for ASC NULLS LAST LIMIT 10) t), '[]'::json) AS meetings_open;

