const parseObj = (v) => typeof v === 'string' ? JSON.parse(v || '{}') : (v || {});
const parseArr = (v) => Array.isArray(v) ? v : (typeof v === 'string' ? JSON.parse(v || '[]') : []);
const stats = parseObj($json.stats);
const overdueTasks = parseArr($json.overdue_tasks);
const approvals = parseArr($json.pending_approvals);
const deadOutbox = parseArr($json.dead_outbox);
const failedEvents = parseArr($json.failed_events);
const docsPending = parseArr($json.docs_pending);
const meetingsOpen = parseArr($json.meetings_open);
const n = (v) => Number(v || 0);
const today = new Date().toISOString().slice(0, 10);
const correlationId = `pmo-governance-${today}`;
let score = 100;
score -= Math.min(25, n(stats.tasks_overdue) * 5);
score -= Math.min(18, n(stats.approvals_high) * 6);
score -= Math.min(18, n(stats.outbox_dead) * 6);
score -= Math.min(15, n(stats.inbox_failed) * 5);
score -= Math.min(10, n(stats.docs_pending) * 2);
score -= Math.min(10, n(stats.actions_overdue) * 3);
score = Math.max(0, score);
const healthStatus = score >= 82 ? 'green' : score >= 62 ? 'yellow' : 'red';
const tomorrow = new Date(Date.now() + 24 * 60 * 60 * 1000).toISOString();
const inTwoDays = new Date(Date.now() + 48 * 60 * 60 * 1000).toISOString();
const raids = [];
const actions = [];
const addRaid = (item) => raids.push({ correlation_id: correlationId, source: 'pmo_governance_engine', status: 'open', ...item });
const addAction = (item) => actions.push({ correlation_id: correlationId, source: 'pmo_governance_engine', status: 'open', ...item });
if (n(stats.tasks_overdue)) {
  addRaid({ item_type: 'issue', title: 'Tareas vencidas sin cierre', description: `${n(stats.tasks_overdue)} tareas vencidas detectadas.`, severity: n(stats.tasks_overdue) > 3 ? 'high' : 'medium', owner: 'PM', impact: 'Riesgo de retraso en entregables.', mitigation: 'Revisar owner, bloquear scope nuevo y acordar fecha real.', due_date: tomorrow, evidence: { overdueTasks } });
  addAction({ title: 'Replanificar tareas vencidas', description: 'Revisar cada tarjeta vencida, confirmar owner y nueva fecha.', owner: 'PM', priority: 'high', due_date: tomorrow, evidence: { overdueTasks } });
}
if (n(stats.approvals_high)) {
  addRaid({ item_type: 'dependency', title: 'Aprobaciones high/critical bloqueando avance', description: `${n(stats.approvals_high)} decisiones requieren aprobación humana.`, severity: 'high', owner: 'Tech Lead', impact: 'Bloqueo de decisiones técnicas o de entrega.', mitigation: 'Resolver en Approval Hub o convocar reunión PM.', due_date: tomorrow, evidence: { approvals } });
  addAction({ title: 'Resolver aprobaciones críticas', description: 'Revisar Approval Hub y decidir aprobar/rechazar con contexto.', owner: 'Tech Lead', priority: 'high', due_date: tomorrow, evidence: { approvals } });
}
if (n(stats.outbox_dead) || n(stats.inbox_failed)) {
  addRaid({ item_type: 'issue', title: 'Falla de confiabilidad en eventos/notificaciones', description: `${n(stats.outbox_dead)} outbox dead, ${n(stats.inbox_failed)} eventos fallidos.`, severity: 'high', owner: 'DevOps / Backend', impact: 'El PM bot puede perder señales o notificaciones.', mitigation: 'Revisar DLQ, replay controlado y error handler.', due_date: tomorrow, evidence: { deadOutbox, failedEvents } });
  addAction({ title: 'Revisar DLQ e inbox fallido', description: 'Ejecutar monitor DLQ y replay solo después de validar causa raíz.', owner: 'DevOps / Backend', priority: 'high', due_date: tomorrow, evidence: { deadOutbox, failedEvents } });
}
if (n(stats.docs_pending)) {
  addRaid({ item_type: 'risk', title: 'Documentos PDF sin resumen PM', description: `${n(stats.docs_pending)} adjuntos pendientes de resumen.`, severity: 'medium', owner: 'Documentacion / QA', impact: 'Se puede perder evidencia de entrega o aceptación.', mitigation: 'Procesar PDFs y extraer decisiones/pendientes.', due_date: inTwoDays, evidence: { docsPending } });
  addAction({ title: 'Procesar PDFs pendientes', description: 'Ejecutar sync de adjuntos y resumen de documentos.', owner: 'Documentacion / QA', priority: 'medium', due_date: inTwoDays, evidence: { docsPending } });
}
if (!meetingsOpen.length && (n(stats.tasks_overdue) || n(stats.approvals_high) || n(stats.outbox_dead))) {
  addAction({ title: 'Convocar reunión de desbloqueo', description: 'Usar PMO - Meeting Coordinator para alinear bloqueos, owners y fechas.', owner: 'PM', priority: 'medium', due_date: tomorrow, evidence: { stats } });
}
const recommendations = actions.map(a => ({ title: a.title, owner: a.owner, due_date: a.due_date, priority: a.priority }));
const summary = healthStatus === 'green'
  ? 'Proyecto estable. Mantener cadencia y monitoreo.'
  : healthStatus === 'yellow'
    ? 'Proyecto con señales de atención. Resolver acciones PMO antes de que escalen.'
    : 'Proyecto en riesgo. Requiere intervención PM inmediata.';
const content = [
  `**PMO Daily Governance - ${today}**`,
  `**Health:** ${healthStatus.toUpperCase()} (${score}/100)`,
  `**Resumen:** ${summary}`,
  '',
  `**Señales:** tareas vencidas ${n(stats.tasks_overdue)}, aprobaciones high ${n(stats.approvals_high)}, outbox dead ${n(stats.outbox_dead)}, docs pendientes ${n(stats.docs_pending)}.`,
  '',
  actions.length ? '**Acciones sugeridas:**' : '**Acciones sugeridas:** Ninguna crítica.',
  ...actions.slice(0, 6).map(a => `- [${a.priority}] ${a.title} -> ${a.owner}`),
  '',
  `Correlation ID: \`${correlationId}\``
].join('\n');
return [{ json: { correlation_id: correlationId, health_score: score, health_status: healthStatus, summary, metrics: stats, recommendations, raids, actions, discord_content: content, idempotency_key: `pmo-governance:${correlationId}:digest` } }];

