CREATE UNIQUE INDEX IF NOT EXISTS pmo_raid_dedupe_idx ON pmo_raid_items (correlation_id, item_type, title) WHERE correlation_id IS NOT NULL;
CREATE UNIQUE INDEX IF NOT EXISTS pmo_action_dedupe_idx ON pmo_action_items (correlation_id, title) WHERE correlation_id IS NOT NULL;
CREATE UNIQUE INDEX IF NOT EXISTS events_outbox_idempotency_key_uq ON events_outbox (idempotency_key);
WITH snapshot AS (
  INSERT INTO pmo_health_snapshots (correlation_id, health_score, health_status, summary, metrics, recommendations)
  VALUES ($1, $2, $3, $4, $5::jsonb, $6::jsonb)
  RETURNING snapshot_id, health_score, health_status
), raid_source AS (
  SELECT * FROM jsonb_to_recordset($7::jsonb) AS x(correlation_id text, item_type text, title text, description text, severity text, probability numeric, impact text, owner text, status text, mitigation text, due_date timestamptz, source text, evidence jsonb)
), raid_insert AS (
  INSERT INTO pmo_raid_items (correlation_id, item_type, title, description, severity, probability, impact, owner, status, mitigation, due_date, source, evidence)
  SELECT correlation_id, item_type, title, description, severity, probability, impact, owner, COALESCE(status,'open'), mitigation, due_date, source, COALESCE(evidence,'{}'::jsonb) FROM raid_source
  ON CONFLICT (correlation_id, item_type, title) WHERE correlation_id IS NOT NULL DO UPDATE SET description = EXCLUDED.description, severity = EXCLUDED.severity, impact = EXCLUDED.impact, mitigation = EXCLUDED.mitigation, due_date = EXCLUDED.due_date, updated_at = NOW()
  RETURNING 1
), action_source AS (
  SELECT * FROM jsonb_to_recordset($8::jsonb) AS x(correlation_id text, source text, title text, description text, owner text, priority text, status text, due_date timestamptz, evidence jsonb)
), action_insert AS (
  INSERT INTO pmo_action_items (correlation_id, source, title, description, owner, priority, status, due_date, evidence)
  SELECT correlation_id, source, title, description, owner, priority, COALESCE(status,'open'), due_date, COALESCE(evidence,'{}'::jsonb) FROM action_source
  ON CONFLICT (correlation_id, title) WHERE correlation_id IS NOT NULL DO UPDATE SET description = EXCLUDED.description, owner = EXCLUDED.owner, priority = EXCLUDED.priority, due_date = EXCLUDED.due_date, evidence = EXCLUDED.evidence, updated_at = NOW()
  RETURNING 1
), outbox AS (
  INSERT INTO events_outbox (event_id, target, action, idempotency_key, payload)
  VALUES (NULL, 'discord', 'notify', $9, $10::jsonb)
  ON CONFLICT (idempotency_key) DO NOTHING
)
SELECT snapshot.snapshot_id, snapshot.health_score, snapshot.health_status, (SELECT COUNT(*) FROM raid_insert) AS raid_count, (SELECT COUNT(*) FROM action_insert) AS action_count FROM snapshot;
